import{_ as t,o,c as i,ae as n}from"./chunks/framework.DrUtF5ir.js";const h=JSON.parse('{"title":"Code of conduct","description":"Elena’s code of conduct for contributors and community members.","frontmatter":{"title":"Code of conduct","description":"Elena’s code of conduct for contributors and community members.","head":[["meta",{"property":"og:title","content":"Code of conduct | Elena"}],["meta",{"property":"og:description","content":"Elena’s code of conduct for contributors and community members."}],["meta",{"name":"twitter:description","content":"Elena’s code of conduct for contributors and community members."}]]},"headers":[{"level":2,"title":"Our pledge","slug":"our-pledge","link":"#our-pledge","children":[]},{"level":2,"title":"Our standards","slug":"our-standards","link":"#our-standards","children":[]},{"level":2,"title":"Our responsibilities","slug":"our-responsibilities","link":"#our-responsibilities","children":[]},{"level":2,"title":"Scope","slug":"scope","link":"#scope","children":[]},{"level":2,"title":"Enforcement","slug":"enforcement","link":"#enforcement","children":[]},{"level":2,"title":"Attribution","slug":"attribution","link":"#attribution","children":[]}],"relativePath":"about/code-of-conduct.md","filePath":"about/code-of-conduct.md","lastUpdated":1774299677000}'),a={name:"about/code-of-conduct.md"};function r(s,e,c,l,d,u){return o(),i("div",null,[...e[0]||(e[0]=[n('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /elena/about/code-of-conduct.md for this page in Markdown format</div><h1 id="code-of-conduct" tabindex="-1">Code of conduct <a class="header-anchor" href="#code-of-conduct" aria-label="Permalink to &quot;Code of conduct&quot;">​</a></h1><h2 id="our-pledge" tabindex="-1">Our pledge <a class="header-anchor" href="#our-pledge" aria-label="Permalink to &quot;Our pledge&quot;">​</a></h2><p>In the interest of fostering an open and welcoming environment, we as contributors and maintainers pledge to make participation in our community a harassment-free experience for everyone, regardless of age, body size, visible or invisible disability, ethnicity, sex characteristics, gender identity and expression, level of experience, education, socio-economic status, nationality, personal appearance, race, religion, or sexual identity and orientation.</p><p>We pledge to act and interact in ways that contribute to an open, welcoming, diverse, inclusive, and healthy community.</p><h2 id="our-standards" tabindex="-1">Our standards <a class="header-anchor" href="#our-standards" aria-label="Permalink to &quot;Our standards&quot;">​</a></h2><p>Examples of behavior that contributes to a positive environment for our community include:</p><ul><li>Demonstrating empathy and kindness toward other people</li><li>Being respectful of differing opinions, viewpoints, and experiences</li><li>Giving and gracefully accepting constructive feedback</li><li>Accepting responsibility and apologizing to those affected by our mistakes, and learning from the experience</li><li>Focusing on what is best not just for us as individuals, but for the overall community</li></ul><p>Examples of unacceptable behavior include:</p><ul><li>The use of sexualized language or imagery, and sexual attention or advances of any kind</li><li>Trolling, insulting or derogatory comments, and personal or political attacks</li><li>Public or private harassment</li><li>Publishing others’ private information, such as a physical or email address, without their explicit permission</li><li>Other conduct which could reasonably be considered inappropriate in a professional setting</li></ul><h2 id="our-responsibilities" tabindex="-1">Our responsibilities <a class="header-anchor" href="#our-responsibilities" aria-label="Permalink to &quot;Our responsibilities&quot;">​</a></h2><p>Project maintainers are responsible for clarifying and enforcing our standards of acceptable behavior and will take appropriate and fair corrective action in response to any behavior that they deem inappropriate, threatening, offensive, or harmful.</p><p>Project maintainers have the right and responsibility to remove, edit, or reject comments, commits, code, wiki edits, issues, and other contributions that are not aligned to this Code of Conduct, and will communicate reasons for moderation decisions when appropriate.</p><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><p>This Code of Conduct applies within all project spaces, and also applies when an individual is representing the project or its community. Examples of representing a project or community include using an official e-mail address, posting via an official social media account, or acting as an appointed representative at an online or offline event.</p><h2 id="enforcement" tabindex="-1">Enforcement <a class="header-anchor" href="#enforcement" aria-label="Permalink to &quot;Enforcement&quot;">​</a></h2><p>Instances of abusive, harassing, or otherwise unacceptable behavior may be reported by contacting the project team at <a href="mailto:hi@elenajs.com" target="_blank" rel="noreferrer">hi@elenajs.com</a>. All complaints will be reviewed and investigated and will result in a response that is deemed necessary and appropriate to the circumstances. The project team is obligated to maintain confidentiality with regard to the reporter of an incident. Further details of specific enforcement policies may be posted separately.</p><p>Project maintainers who do not follow or enforce the Code of Conduct in good faith may face temporary or permanent repercussions as determined by other members of the project’s leadership.</p><h2 id="attribution" tabindex="-1">Attribution <a class="header-anchor" href="#attribution" aria-label="Permalink to &quot;Attribution&quot;">​</a></h2><p>This Code of Conduct is adapted from the <a href="https://www.contributor-covenant.org/" target="_blank" rel="noreferrer">Contributor Covenant</a>, version 2.0, available at <a href="https://www.contributor-covenant.org/version/2/0/code_of_conduct.html" target="_blank" rel="noreferrer">https://www.contributor-covenant.org/version/2/0/code_of_conduct.html</a>.</p><p>For answers to common questions about this code of conduct, see <a href="https://www.contributor-covenant.org/faq" target="_blank" rel="noreferrer">https://www.contributor-covenant.org/faq</a>.</p>',21)])])}const m=t(a,[["render",r]]);export{h as __pageData,m as default};
